message.content:
{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラを本日（2026年5月13日）をもって正式キックオフし、発足とすること。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "週次定例会議を毎週水曜日の10時より開催し、参加は各部署から1名（代理可）とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "データ移行において、第1フェーズではマスタデータのみを移行し、トランザクション履歴は旧システムで参照用に残すこと。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "認証およびマスタ配信の基盤として、サクラ商事との共同利用（第3案）を採用すること。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "開発ベンダーとしてコマツバ・ソリューションズを選定し、社内稟議を進めること。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "システム移行方式を、拠点をグループに分けて段階的に切り替える方法（B案）とすること。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "本番リリースの目標日を、9月末から10月15日に変更し、各拠点への切り替え作業は土曜日の深夜帯に行うこと。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D8",
      "content": "新システムにおけるユーザー権限のロール定義は、既存のまま流用し、新規設計は行わず後日の運用改善として扱うこと。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D9",
      "content": "障害発生時の一次受付窓口を、情報システム部から品質保証部（QA）に変更すること。",
      "decided_by": "桐生 遥"
    }
  ],
  "action_items": [
    {
      "id": "A1",
      "task": "外部連携のAPI仕様書ドラフトを作成し、共有する。",
      "assignee": "芦田 巧",
      "due": "2026-05-20"
    },
    {
      "id": "A2",
      "task": "検証環境用のサーバ調達依頼を出す。",
      "assignee": "沼田 賢一",
      "due": "2026-05-15"
    },
    {
      "id": "A3",
      "task": "現場ヒアリングの対象となる部署および窓口のリストを作成し、提出する。",
      "assignee": "東雲 美咲",
      "due": "2026-05-19"
    },
    {
      "id": "A4",
      "task": "開発ベンダー選定に関する社内稟議を起票する。",
      "assignee": "郡司 明久",
      "due": "2026-05-18"
    },
    {
      "id": "A5",
      "task": "サクラ商事への共同利用承認の回答書を作成し、送付する。",
      "assignee": "桐生 遥",
      "due": "2026-05-19"
    },
    {
      "id": "A6",
